export type Genre = 'synthwave' | 'lofi' | 'house' | 'ambient' | 'acoustic';

export interface Track {
  id: string;
  title: string;
  artist: string;
  album: string;
  duration: number;
  gradient: string;
  genre: Genre;
  lyrics?: string[];
  color: string;
  fileUrl: string;
  coverUrl: string;
}

export interface Playlist {
  id: string;
  title: string;
  description: string;
  coverGradient: string;
  tracks: Track[];
  likes: string;
  followers: string;
  primaryColor: string;
}

export interface Category {
  id: string;
  title: string;
  color: string;
}

type RawSong = {
  id: number;
  title: string;
  artist: string;
  album: string;
  duration: number;
  url: string;
  cover: string;
};

